import sys

class Solution:
    def __init__(self):
        self.front = self.rear = -1
        self.arr = [
        ]

    def push(self, x) -> None:
        self.arr.append(x)
        if self.rear == len(self.arr) - 2:
            self.arr.extend([0, 0])
            self.rear += 2
        self.rear += 1

    def pop(self) -> None:
        if self.front == self.rear:
            self.front = self.rear = -1
        else:
            self.front += 1

    def front(self) -> int:
        return self.arr[self.front]


def main():
    s = Solution()
    n = int(input())
    for _ in range(n):
        op = input().split()
        if op[0] == 'push':
            s.push(int(op[1]))
        elif op[0] == 'pop':
            s.pop()
        elif op[0] == 'front':
            print(s.front())

if __name__ == '__main__':
    main()

