#include <iostream>

using namespace std;

class Solution {
public:
    void push(int x) { if (rear == front) { arr[front << 1] = 0; arr[front << 1 | 1] = 0; rear = rear << 1; } arr[rear++] = x; }
    void pop() { if (front == rear) front = rear = -1; else { front++; } }
    int front() { return arr[front]; }
private:
    int front, rear;
    int arr[10001];
};

int main()
{
    int n;
    cin >> n;
    Solution s;
    for (int i = 0; i < n; i++)
    {
        char op;
        int x;
        cin >> op >> x;
        if (op == 'p')
        {
            s.push(x);
        }
        else if (op == 'o')
        {
            s.pop();
        }
        else if (op == 'f')
        {
            cout << s.front();
        }
    }
    return 0;
}
